def search_best_matches_texts(texts, norm_query, topk=10):
    results = []
    for idx, t in enumerate(texts):
        nt = normalize_arabic(t)
        score = sim_score(norm_query, nt)
        if score > 0:
            results.append((score, idx, t, nt))
    results.sort(reverse=True, key=lambda x: x[0])
    return results[:topk]

